INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Steh auf und verbeuge dich vor der Gruppe!"},"en":{"text":"Stand up and take a bow to the group!"},"es":{"text":"Levantate y haz una reverencia al grupo!"},"fr":{"text":"Leve-toi et fais une reverence au groupe!"},"it":{"text":"Alzati e fai un inchino al gruppo!"},"nl":{"text":"Sta op en maak een buiging voor de groep!"},"pl":{"text":"Wstan i uklonij sie grupie!"},"pt":{"text":"Levanta-te e faz uma venia ao grupo!"},"tr":{"text":"Ayaga kalk ve gruba selam ver!"},"ar":{"text":"قف وانحن للمجموعة!"}}', '1', 'Harmlos', true);
