INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Buchstabiere deinen Namen rueckwaerts laut!"},"en":{"text":"Spell your name backwards out loud!"},"es":{"text":"Deletrea tu nombre al reves en voz alta!"},"fr":{"text":"Epelle ton prenom a l\\"},"it":{"text":"Compita il tuo nome al contrario ad alta voce!"},"nl":{"text":"Spel je naam achterstevoren hardop!"},"pl":{"text":"Przeliteruj swoje imie od tylu na glos!"},"pt":{"text":"Soletra o teu nome ao contrario em voz alta!"},"tr":{"text":"Adini tersten yuksek sesle hecele!"},"ar":{"text":"تهج اسمك بالمقلوب بصوت عال!"}}', '1', 'Harmlos', true);
