INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle der Gruppe dein peinlichstes Erlebnis als Kind!"},"en":{"text":"Tell the group your most embarrassing childhood moment!"},"es":{"text":"Cuenta al grupo tu momento mas vergonzoso de nino!"},"fr":{"text":"Raconte au groupe ton moment le plus genant d\\"},"it":{"text":"Racconta al gruppo il tuo momento piu imbarazzante da bambino!"},"nl":{"text":"Vertel de groep je gênantste moment als kind!"},"pl":{"text":"Opowiedz grupie swoj najbardziej zenujacy moment z dziecinstwa!"},"pt":{"text":"Conta ao grupo o teu momento mais embaracoso de crianca!"},"tr":{"text":"Gruba cocukluktan en utandirici anini anlat!"},"ar":{"text":"احك للمجموعة اكثر لحظة محرجة من طفولتك!"}}', '1', 'Harmlos', true);
