INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Fuehre den schlechtesten Tanzstil vor, den du kennst!"},"en":{"text":"Show off the worst dance move you know!"},"es":{"text":"Ensena el peor paso de baile que conozcas!"},"fr":{"text":"Montre le pire pas de danse que tu connaisses!"},"it":{"text":"Mostra il peggior passo di ballo che conosci!"},"nl":{"text":"Laat de slechtste danspas zien die je kent!"},"pl":{"text":"Pokaz najgorszy krok taneczny, jaki znasz!"},"pt":{"text":"Mostra o pior passo de danca que conheces!"},"tr":{"text":"Bildigin en kotu dans adimini goster!"},"ar":{"text":"اعرض اسوا خطوة رقص تعرفها!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle eine Geschichte, in der jedes Wort mit dem gleichen Buchstaben beginnt!"},"en":{"text":"Tell a story where every word starts with the same letter!"},"es":{"text":"Cuenta una historia donde cada palabra empiece con la misma letra!"},"fr":{"text":"Raconte une histoire ou chaque mot commence par la meme lettre!"},"it":{"text":"Racconta una storia dove ogni parola inizia con la stessa lettera!"},"nl":{"text":"Vertel een verhaal waarbij elk woord met dezelfde letter begint!"},"pl":{"text":"Opowiedz historie, gdzie kazde slowo zaczyna sie ta sama litera!"},"pt":{"text":"Conta uma historia onde cada palavra comeca com a mesma letra!"},"tr":{"text":"Her kelimesi ayni harfle baslayan bir hikaye anlat!"},"ar":{"text":"احك قصة كل كلمة فيها تبدا بنفس الحرف!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Steh auf und halte eine Dankesrede wie bei den Oscars!"},"en":{"text":"Stand up and give an Oscar acceptance speech!"},"es":{"text":"Levantate y da un discurso de agradecimiento como en los Oscar!"},"fr":{"text":"Leve-toi et fais un discours de remerciement comme aux Oscars!"},"it":{"text":"Alzati e tieni un discorso di ringraziamento come agli Oscar!"},"nl":{"text":"Sta op en houd een Oscar-dankwoord!"},"pl":{"text":"Wstan i wyglos przemowienie jak na Oscarach!"},"pt":{"text":"Levanta-te e faz um discurso de agradecimento como nos Oscares!"},"tr":{"text":"Ayaga kalk ve Oscar oduel konusmasi yap!"},"ar":{"text":"قف والق خطاب شكر كما في الاوسكار!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach ein Tik-Tok-Video (ohne es zu posten)!"},"en":{"text":"Make a TikTok video (without posting it)!"},"es":{"text":"Haz un video de TikTok (sin publicarlo)!"},"fr":{"text":"Fais une video TikTok (sans la publier)!"},"it":{"text":"Fai un video TikTok (senza postarlo)!"},"nl":{"text":"Maak een TikTok-video (zonder te posten)!"},"pl":{"text":"Nagraj filmik na TikToka (nie publikuj go)!"},"pt":{"text":"Faz um video TikTok (sem publicar)!"},"tr":{"text":"TikTok videosu cek (yayinlama)!"},"ar":{"text":"صور فيديو تيك توك (بدون نشره)!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Singe Happy Birthday fürdie Person gegenüber!"},"en":{"text":"Sing Happy Birthday to the person across from you!"},"es":{"text":"Canta Cumpleanos Feliz a la persona de enfrente!"},"fr":{"text":"Chante Joyeux Anniversaire a la personne en face!"},"it":{"text":"Canta Tanti Auguri alla persona di fronte!"},"nl":{"text":"Zing Happy Birthday voor de persoon tegenover je!"},"pl":{"text":"Zaspiewaj Happy Birthday osobie naprzeciwko!"},"pt":{"text":"Canta Parabens a Voce para a pessoa a frente!"},"tr":{"text":"Karsindaki kisiye Dogum Gunun Kutlu Olsun soyle!"},"ar":{"text":"غن عيد ميلاد سعيد للشخص المقابل!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sprich 1 Minute lang wie Yoda!"},"en":{"text":"Speak like Yoda for 1 minute!"},"es":{"text":"Habla como Yoda durante 1 minuto!"},"fr":{"text":"Parle comme Yoda pendant 1 minute!"},"it":{"text":"Parla come Yoda per 1 minuto!"},"nl":{"text":"Praat 1 minuut als Yoda!"},"pl":{"text":"Mow jak Yoda przez 1 minute!"},"pt":{"text":"Fala como o Yoda durante 1 minuto!"},"tr":{"text":"1 dakika Yoda gibi konus!"},"ar":{"text":"تحدث مثل يودا لمدة دقيقة!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Fuehre den beruehmtesten Tanz aus einem Musikvideo vor!"},"en":{"text":"Perform the most famous dance from a music video!"},"es":{"text":"Haz el baile mas famoso de un videoclip!"},"fr":{"text":"Reproduis la danse la plus celebre d\\"},"it":{"text":"Rifai il ballo piu famoso di un video musicale!"},"nl":{"text":"Doe de beroemdste dans uit een videoclip!"},"pl":{"text":"Odtworz najslynniejszy taniec z klipu!"},"pt":{"text":"Reproduz a danca mais famosa de um videoclip!"},"tr":{"text":"Bir klipten en unlu dansi yap!"},"ar":{"text":"قلد اشهر رقصة من فيديو كليب!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach eine dramatische Lesung des letzten Texts auf deinem Handy!"},"en":{"text":"Do a dramatic reading of the last text on your phone!"},"es":{"text":"Haz una lectura dramatica del ultimo mensaje de tu movil!"},"fr":{"text":"Fais une lecture dramatique du dernier SMS sur ton telephone!"},"it":{"text":"Fai una lettura drammatica dell\\"},"nl":{"text":"Doe een dramatische voorlezing van het laatste bericht op je telefoon!"},"pl":{"text":"Zrob dramatyczne czytanie ostatniego SMSa na telefonie!"},"pt":{"text":"Faz uma leitura dramatica da ultima mensagem no teu telemovel!"},"tr":{"text":"Telefonundaki son mesaji dramatik sekilde oku!"},"ar":{"text":"اقرا اخر رسالة على هاتفك بشكل درامي!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Versuche 30 Sekunden lang nicht zu blinzeln!"},"en":{"text":"Try not to blink for 30 seconds!"},"es":{"text":"Intenta no parpadear durante 30 segundos!"},"fr":{"text":"Essaie de ne pas cligner des yeux pendant 30 secondes!"},"it":{"text":"Prova a non battere le palpebre per 30 secondi!"},"nl":{"text":"Probeer 30 seconden niet te knipperen!"},"pl":{"text":"Sprobuj nie mrugac przez 30 sekund!"},"pt":{"text":"Tenta nao piscar durante 30 segundos!"},"tr":{"text":"30 saniye gozunu kirpmamaya calis!"},"ar":{"text":"حاول الا ترمش لمدة 30 ثانية!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle einen Zungenbrecher dreimal schnell hintereinander!"},"en":{"text":"Say a tongue twister three times fast!"},"es":{"text":"Di un trabalenguas tres veces rapido!"},"fr":{"text":"Dis un virelangue trois fois vite!"},"it":{"text":"Di uno scioglilingua tre volte veloce!"},"nl":{"text":"Zeg een tongbreker drie keer snel!"},"pl":{"text":"Powiedz lamaniec jezykowy trzy razy szybko!"},"pt":{"text":"Diz um trava-linguas tres vezes rapido!"},"tr":{"text":"Bir tekerleme üc kez hizlica soyle!"},"ar":{"text":"قل سجعة ثلاث مرات بسرعة!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach einen Handstand (oder versuch es zumindest)!"},"en":{"text":"Do a handstand (or at least try)!"},"es":{"text":"Haz el pino (o intentalo)!"},"fr":{"text":"Fais le poirier (ou essaie)!"},"it":{"text":"Fai la verticale (o almeno provaci)!"},"nl":{"text":"Doe een handstand (of probeer het)!"},"pl":{"text":"Zrob stojke na rekach (lub sprobuj)!"},"pt":{"text":"Faz o pino (ou pelo menos tenta)!"},"tr":{"text":"Amuda kalk (veya dene)!"},"ar":{"text":"اعمل وقوف على اليدين (او حاول)!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Imitiere dein Lieblingsemoji mit deinem Gesicht!"},"en":{"text":"Imitate your favorite emoji with your face!"},"es":{"text":"Imita tu emoji favorito con la cara!"},"fr":{"text":"Imite ton emoji prefere avec ton visage!"},"it":{"text":"Imita la tua emoji preferita con il viso!"},"nl":{"text":"Doe je favoriete emoji na met je gezicht!"},"pl":{"text":"Nasladuj swoje ulubione emoji twarz!"},"pt":{"text":"Imita o teu emoji favorito com a cara!"},"tr":{"text":"En sevdigin emojiyi yuzunle taklit et!"},"ar":{"text":"قلد الايموجي المفضل لديك بوجهك!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Ruf jemanden an und sag \"Ich liebe dich!\""},"en":{"text":"Call someone and say \"I love you!\""},"es":{"text":"Llama a alguien y dile \"Te quiero!\""},"fr":{"text":"Appelle quelqu\\"},"it":{"text":"Chiama qualcuno e digli \"Ti amo!\""},"nl":{"text":"Bel iemand en zeg \"Ik hou van je!\""},"pl":{"text":"Zadzwon do kogos i powiedz \"Kocham Cie!\""},"pt":{"text":"Liga a alguem e diz \"Amo-te!\""},"tr":{"text":"Birini ara ve \"Seni seviyorum!\" de!"},"ar":{"text":"اتصل بشخص وقل \"احبك!\""}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Poste ein Selfie mit dem duesteren Caption \"Montag...\"!"},"en":{"text":"Post a selfie with the caption \"Monday...\"!"},"es":{"text":"Sube un selfie con el pie de foto \"Lunes...\"!"},"fr":{"text":"Poste un selfie avec la legende \"Lundi...\"!"},"it":{"text":"Posta un selfie con la didascalia \"Lunedi...\"!"},"nl":{"text":"Post een selfie met bijschrift \"Maandag...\"!"},"pl":{"text":"Wrzuc selfie z podpisem \"Poniedzialek...\"!"},"pt":{"text":"Publica uma selfie com a legenda \"Segunda-feira...\"!"},"tr":{"text":"\"Pazartesi...\" yazisiyla selfie paylas!"},"ar":{"text":"انشر سيلفي مع التعليق \"الاثنين...\"!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lass die Gruppe ein Foto von dir machen und es als Profilbild setzen!"},"en":{"text":"Let the group take a photo of you and set it as your profile pic!"},"es":{"text":"Deja que el grupo te haga una foto y ponla de perfil!"},"fr":{"text":"Laisse le groupe prendre une photo et la mettre en photo de profil!"},"it":{"text":"Lascia che il gruppo ti faccia una foto e la metta come profilo!"},"nl":{"text":"Laat de groep een foto maken en als profielfoto instellen!"},"pl":{"text":"Pozwol grupie zrobic ci zdjecie i ustawic je jako profilowe!"},"pt":{"text":"Deixa o grupo tirar-te uma foto e coloca-la como foto de perfil!"},"tr":{"text":"Grubun sana foto cekip profil yapmaisna izin ver!"},"ar":{"text":"دع المجموعة تلتقط صورتك وتضعها كصورة بروفايل!"}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle deinen größten Fail beim Flirten!"},"en":{"text":"Tell your biggest flirting fail!"},"es":{"text":"Cuenta tu mayor fracaso ligando!"},"fr":{"text":"Raconte ton plus grand echec de drague!"},"it":{"text":"Racconta il tuo peggior tentativo di flirtare!"},"nl":{"text":"Vertel je grootste flirt-blunder!"},"pl":{"text":"Opowiedz swoja najwieksza wpadke przy podrywaniu!"},"pt":{"text":"Conta o teu maior fracasso a engatar!"},"tr":{"text":"En buyuk flort basarisizligini anlat!"},"ar":{"text":"احك اكبر فشل في المغازلة!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Zeige der Gruppe die letzten 3 Fotos auf deinem Handy!"},"en":{"text":"Show the group the last 3 photos on your phone!"},"es":{"text":"Ensena al grupo las ultimas 3 fotos de tu movil!"},"fr":{"text":"Montre au groupe les 3 dernieres photos de ton telephone!"},"it":{"text":"Mostra al gruppo le ultime 3 foto del telefono!"},"nl":{"text":"Laat de groep de laatste 3 foto\\"},"pl":{"text":"Pokaz grupie 3 ostatnie zdjecia w telefonie!"},"pt":{"text":"Mostra ao grupo as ultimas 3 fotos do teu telemovel!"},"tr":{"text":"Telefonundaki son 3 fotoyu gruba goster!"},"ar":{"text":"ارِ المجموعة اخر 3 صور على هاتفك!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sag jedem in der Runde ein ehrliches Kompliment!"},"en":{"text":"Give everyone in the group an honest compliment!"},"es":{"text":"Dile a cada uno del grupo un cumplido sincero!"},"fr":{"text":"Fais un compliment sincere a chaque personne du groupe!"},"it":{"text":"Fai un complimento sincero a ogni persona del gruppo!"},"nl":{"text":"Geef iedereen in de groep een eerlijk compliment!"},"pl":{"text":"Powiedz kazdemu w grupie szczery komplement!"},"pt":{"text":"Faz um elogio sincero a cada pessoa do grupo!"},"tr":{"text":"Gruptaki herkese samimi bir iltifat et!"},"ar":{"text":"قل لكل شخص في المجموعة مجاملة صادقة!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lass jemanden eine Nachricht von deinem Handy schicken!"},"en":{"text":"Let someone send a message from your phone!"},"es":{"text":"Deja que alguien envie un mensaje desde tu movil!"},"fr":{"text":"Laisse quelqu\\"},"it":{"text":"Lascia che qualcuno mandi un messaggio dal tuo telefono!"},"nl":{"text":"Laat iemand een bericht sturen vanaf jouw telefoon!"},"pl":{"text":"Pozwol komus wyslac wiadomosc z twojego telefonu!"},"pt":{"text":"Deixa alguem enviar uma mensagem do teu telemovel!"},"tr":{"text":"Birinin telefonundan mesaj gondermesine izin ver!"},"ar":{"text":"دع شخصا يرسل رسالة من هاتفك!"}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Stelle dich auf einen Stuhl und singe ein Liebeslied!"},"en":{"text":"Stand on a chair and sing a love song!"},"es":{"text":"Subete a una silla y canta una cancion de amor!"},"fr":{"text":"Monte sur une chaise et chante une chanson d\\"},"it":{"text":"Sali su una sedia e canta una canzone d\\"},"nl":{"text":"Ga op een stoel staan en zing een liefdeslied!"},"pl":{"text":"Wstan na krzeslo i spiewaj piosenke milosna!"},"pt":{"text":"Sobe para uma cadeira e canta uma musica de amor!"},"tr":{"text":"Sandalyeye cik ve bir ask sarkisi soyle!"},"ar":{"text":"قف على كرسي وغن اغنية حب!"}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lass die Gruppe dein Outfit fürden nächsten Tag bestimmen!"},"en":{"text":"Let the group decide your outfit for tomorrow!"},"es":{"text":"Deja que el grupo decida tu ropa de manana!"},"fr":{"text":"Laisse le groupe choisir ta tenue de demain!"},"it":{"text":"Lascia che il gruppo scelga il tuo outfit per domani!"},"nl":{"text":"Laat de groep je outfit voor morgen kiezen!"},"pl":{"text":"Pozwol grupie wybrac twoj stroj na jutro!"},"pt":{"text":"Deixa o grupo escolher a tua roupa para amanha!"},"tr":{"text":"Grubun yarin kiyafetini secmesine izin ver!"},"ar":{"text":"دع المجموعة تختار ملابسك لغد!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lies laut die letzte Nachricht vor, die du gesendet hast!"},"en":{"text":"Read aloud the last message you sent!"},"es":{"text":"Lee en voz alta el ultimo mensaje que enviaste!"},"fr":{"text":"Lis a voix haute le dernier message que tu as envoye!"},"it":{"text":"Leggi ad alta voce l\\"},"nl":{"text":"Lees het laatste bericht dat je stuurde hardop voor!"},"pl":{"text":"Przeczytaj na glos ostatnia wiadomosc, ktora wyslales!"},"pt":{"text":"Le em voz alta a ultima mensagem que enviaste!"},"tr":{"text":"Gonderdigin son mesaji yuksek sesle oku!"},"ar":{"text":"اقرا اخر رسالة ارسلتها بصوت عال!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach ein peinliches Foto und sende es an deinen besten Freund!"},"en":{"text":"Take an embarrassing photo and send it to your best friend!"},"es":{"text":"Hazte una foto vergonzosa y mandala a tu mejor amigo!"},"fr":{"text":"Prends une photo genante et envoie-la a ton meilleur ami!"},"it":{"text":"Fai una foto imbarazzante e mandala al tuo migliore amico!"},"nl":{"text":"Maak een gênante foto en stuur het naar je beste vriend!"},"pl":{"text":"Zrob zenujace zdjecie i wyslij najlepszemu przyjacielowi!"},"pt":{"text":"Tira uma foto embaracosa e envia ao teu melhor amigo!"},"tr":{"text":"Utandirici bir foto cek ve en iyi arkadasina gonder!"},"ar":{"text":"التقط صورة محرجة وارسلها لصديقك المقرب!"}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Gib der Person links von dir einen Spitznamen!"},"en":{"text":"Give the person to your left a nickname!"},"es":{"text":"Ponle un mote a la persona de tu izquierda!"},"fr":{"text":"Donne un surnom a la personne a ta gauche!"},"it":{"text":"Dai un soprannome alla persona alla tua sinistra!"},"nl":{"text":"Geef de persoon links een bijnaam!"},"pl":{"text":"Daj przezwisko osobie po lewej!"},"pt":{"text":"Da uma alcunha a pessoa a tua esquerda!"},"tr":{"text":"Solundaki kisiye bir lakap tak!"},"ar":{"text":"اعط لقبا للشخص على يسارك!"}}', '1', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle die peinlichste Geschichte aus deiner Schulzeit!"},"en":{"text":"Tell the most embarrassing story from your school days!"},"es":{"text":"Cuenta la historia mas vergonzosa del colegio!"},"fr":{"text":"Raconte l\\"},"it":{"text":"Racconta la storia piu imbarazzante della scuola!"},"nl":{"text":"Vertel het gênantste verhaal uit je schooltijd!"},"pl":{"text":"Opowiedz najbardziej zenujaca historie ze szkoly!"},"pt":{"text":"Conta a historia mais embaracosa da tua escola!"},"tr":{"text":"Okuldan en utandirici hikayeni anlat!"},"ar":{"text":"احك اكثر قصة محرجة من ايام المدرسة!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach ein Foto mit dem laecherlichsten Gesichtsausdruck!"},"en":{"text":"Take a photo with the most ridiculous facial expression!"},"es":{"text":"Hazte una foto con la cara mas ridicula!"},"fr":{"text":"Prends une photo avec l\\"},"it":{"text":"Fai una foto con l\\"},"nl":{"text":"Maak een foto met de belachelijkste gezichtsuitdrukking!"},"pl":{"text":"Zrob zdjecie z najsmieszniejsza mina!"},"pt":{"text":"Tira uma foto com a expressao mais ridicula!"},"tr":{"text":"En sacma yuz ifadesiyle bir foto cek!"},"ar":{"text":"التقط صورة باسخف تعبير وجه!"}}', '1', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Schreibe und sende eine poetische Nachricht an den letzten Kontakt!"},"en":{"text":"Write and send a poetic message to your last contact!"},"es":{"text":"Escribe y envia un mensaje poetico al ultimo contacto!"},"fr":{"text":"Ecris et envoie un message poetique a ton dernier contact!"},"it":{"text":"Scrivi e invia un messaggio poetico all\\"},"nl":{"text":"Schrijf en stuur een poetisch bericht naar je laatste contact!"},"pl":{"text":"Napisz i wyslij poetycka wiadomosc do ostatniego kontaktu!"},"pt":{"text":"Escreve e envia uma mensagem poetica ao ultimo contacto!"},"tr":{"text":"Son kisiye siirsel bir mesaj yaz ve gonder!"},"ar":{"text":"اكتب وارسل رسالة شعرية لاخر جهة اتصال!"}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Fuehre deine beste Model-Pose vor!"},"en":{"text":"Strike your best model pose!"},"es":{"text":"Haz tu mejor pose de modelo!"},"fr":{"text":"Fais ta meilleure pose de mannequin!"},"it":{"text":"Fai la tua migliore posa da modella!"},"nl":{"text":"Doe je beste modelpose!"},"pl":{"text":"Zrob najlepsza poze modelki!"},"pt":{"text":"Faz a tua melhor pose de modelo!"},"tr":{"text":"En iyi model pozunu ver!"},"ar":{"text":"اعمل افضل وضعية عارضة ازياء!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle, was du heimlich überdie Person gegenüber denkst!"},"en":{"text":"Tell the group what you secretly think about the person across from you!"},"es":{"text":"Dile al grupo lo que piensas en secreto de la persona de enfrente!"},"fr":{"text":"Dis au groupe ce que tu penses secretement de la personne en face!"},"it":{"text":"Di al gruppo cosa pensi segretamente della persona di fronte!"},"nl":{"text":"Vertel de groep wat je stiekem denkt over de persoon tegenover je!"},"pl":{"text":"Powiedz grupie, co naprawde myslisz o osobie naprzeciwko!"},"pt":{"text":"Diz ao grupo o que pensas secretamente sobre a pessoa a frente!"},"tr":{"text":"Karsinidaki kisi hakkinda gizlice ne dusunduugunu soyle!"},"ar":{"text":"اخبر المجموعة بما تفكر به سرا عن الشخص المقابل!"}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lass die Gruppe deine Haare stylen!"},"en":{"text":"Let the group style your hair!"},"es":{"text":"Deja que el grupo te peine!"},"fr":{"text":"Laisse le groupe te coiffer!"},"it":{"text":"Lascia che il gruppo ti pettini!"},"nl":{"text":"Laat de groep je haar stylen!"},"pl":{"text":"Pozwol grupie ci uczesac!"},"pt":{"text":"Deixa o grupo pentear-te!"},"tr":{"text":"Grubun sacini yapmaisna izin ver!"},"ar":{"text":"دع المجموعة تصفف شعرك!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Singe den Refrain deines Lieblingssongs vor allen!"},"en":{"text":"Sing the chorus of your favorite song in front of everyone!"},"es":{"text":"Canta el estribillo de tu cancion favorita delante de todos!"},"fr":{"text":"Chante le refrain de ta chanson preferee devant tout le monde!"},"it":{"text":"Canta il ritornello della tua canzone preferita davanti a tutti!"},"nl":{"text":"Zing het refrein van je favoriete liedje voor iedereen!"},"pl":{"text":"Zaspiewaj refren ulubionej piosenki przed wszystkimi!"},"pt":{"text":"Canta o refrão da tua musica favorita em frente a todos!"},"tr":{"text":"En sevdigin sarkinin nakratini herkesin onunde soyle!"},"ar":{"text":"غن لازمة اغنيتك المفضلة امام الجميع!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach 5 Liegestütze und zaehle dabei laut auf Franzoesisch!"},"en":{"text":"Do 5 push-ups and count in French!"},"es":{"text":"Haz 5 flexiones contando en frances!"},"fr":{"text":"Fais 5 pompes en comptant en anglais!"},"it":{"text":"Fai 5 flessioni contando in francese!"},"nl":{"text":"Doe 5 push-ups en tel in het Frans!"},"pl":{"text":"Zrob 5 pompek liczac po francusku!"},"pt":{"text":"Faz 5 flexoes a contar em frances!"},"tr":{"text":"Fransizca sayarak 5 sinav cek!"},"ar":{"text":"اعمل 5 ضغطات وعد بالفرنسية!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Ruf einen Freund an und tu so, als würdest du etwas gestehen!"},"en":{"text":"Call a friend and pretend you are confessing something!"},"es":{"text":"Llama a un amigo y finge que le estas confesando algo!"},"fr":{"text":"Appelle un ami et fais semblant de lui avouer quelque chose!"},"it":{"text":"Chiama un amico e fingi di confessare qualcosa!"},"nl":{"text":"Bel een vriend en doe alsof je iets opbiecht!"},"pl":{"text":"Zadzwon do przyjaciela i udawaj, ze cos wyznajesz!"},"pt":{"text":"Liga a um amigo e finge que estas a confessar algo!"},"tr":{"text":"Bir arkadasini ara ve itiraf ediyormus gibi yap!"},"ar":{"text":"اتصل بصديق وتظاهر بانك تعترف بشيء!"}}', '3', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Geh raus und ruf laut \"Ich bin der/die Beste!\""},"en":{"text":"Go outside and shout \"I am the best!\""},"es":{"text":"Sal fuera y grita \"Soy el/la mejor!\""},"fr":{"text":"Sors et crie \"Je suis le/la meilleur(e)!\""},"it":{"text":"Esci e grida \"Sono il/la migliore!\""},"nl":{"text":"Ga naar buiten en schreeuw \"Ik ben de beste!\""},"pl":{"text":"Wyjdz na zewnatrz i krzyknij \"Jestem najlepszy/a!\""},"pt":{"text":"Vai la fora e grita \"Eu sou o/a melhor!\""},"tr":{"text":"Disari cik ve \"Ben en iyiyim!\" diye bagir!"},"ar":{"text":"اخرج واصرخ \"انا الافضل!\""}}', '3', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Iss etwas, das die Gruppe fürdich zusammenmischt!"},"en":{"text":"Eat something the group mixes together for you!"},"es":{"text":"Come algo que el grupo mezcle para ti!"},"fr":{"text":"Mange quelque chose que le groupe melange pour toi!"},"it":{"text":"Mangia qualcosa che il gruppo mescola per te!"},"nl":{"text":"Eet iets dat de groep voor je mixt!"},"pl":{"text":"Zjedz cos, co grupa ci przygotuje!"},"pt":{"text":"Come algo que o grupo misture para ti!"},"tr":{"text":"Grubun senin icin karistirdigi bir seyi ye!"},"ar":{"text":"كل شيئا تخلطه المجموعة لك!"}}', '3', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach 30 Sekunden lang Beatbox vor der Gruppe!"},"en":{"text":"Beatbox for 30 seconds in front of the group!"},"es":{"text":"Haz beatbox 30 segundos delante del grupo!"},"fr":{"text":"Fais du beatbox pendant 30 secondes devant le groupe!"},"it":{"text":"Fai beatbox per 30 secondi davanti al gruppo!"},"nl":{"text":"Beatbox 30 seconden voor de groep!"},"pl":{"text":"Beatboxuj 30 sekund przed grupa!"},"pt":{"text":"Faz beatbox durante 30 segundos em frente ao grupo!"},"tr":{"text":"30 saniye grubun onunde beatbox yap!"},"ar":{"text":"اعمل بيتبوكس 30 ثانية امام المجموعة!"}}', '2', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Tanz alleine 1 Minute zu einem Song, den die Gruppe waehlt!"},"en":{"text":"Dance alone for 1 minute to a song the group picks!"},"es":{"text":"Baila solo 1 minuto con una cancion que elija el grupo!"},"fr":{"text":"Danse seul 1 minute sur un morceau choisi par le groupe!"},"it":{"text":"Balla da solo 1 minuto con una canzone scelta dal gruppo!"},"nl":{"text":"Dans alleen 1 minuut op een liedje dat de groep kiest!"},"pl":{"text":"Tancz sam 1 minute do piosenki wybranej przez grupe!"},"pt":{"text":"Danca sozinho 1 minuto com uma musica escolhida pelo grupo!"},"tr":{"text":"Grubun sectigi sarkiyla 1 dakika tek basina dans et!"},"ar":{"text":"ارقص وحدك دقيقة على اغنية تختارها المجموعة!"}}', '3', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lass die Gruppe eine Nachricht in deinem Status posten!"},"en":{"text":"Let the group post a message on your status!"},"es":{"text":"Deja que el grupo publique un mensaje en tu estado!"},"fr":{"text":"Laisse le groupe poster un message sur ton statut!"},"it":{"text":"Lascia che il gruppo pubblichi un messaggio sul tuo stato!"},"nl":{"text":"Laat de groep een bericht op je status plaatsen!"},"pl":{"text":"Pozwol grupie wrzucic wiadomosc na twoj status!"},"pt":{"text":"Deixa o grupo publicar uma mensagem no teu estado!"},"tr":{"text":"Grubun durumuna mesaj yayinlamasina izin ver!"},"ar":{"text":"دع المجموعة تنشر رسالة على حالتك!"}}', '3', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sprich die nächsten 3 Runden in Reimen!"},"en":{"text":"Speak in rhymes for the next 3 rounds!"},"es":{"text":"Habla en rima las proximas 3 rondas!"},"fr":{"text":"Parle en rimes pendant les 3 prochains tours!"},"it":{"text":"Parla in rima per i prossimi 3 turni!"},"nl":{"text":"Praat in rijm de komende 3 rondes!"},"pl":{"text":"Mow w rymach przez nastepne 3 rundy!"},"pt":{"text":"Fala em rima nas proximas 3 rondas!"},"tr":{"text":"Sonraki 3 tur kafiyeli konus!"},"ar":{"text":"تحدث بالسجع في الجولات الثلاث القادمة!"}}', '2', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach ein TikTok-Video und poste es wirklich!"},"en":{"text":"Make a TikTok video and actually post it!"},"es":{"text":"Haz un video de TikTok y publicalo de verdad!"},"fr":{"text":"Fais une video TikTok et poste-la vraiment!"},"it":{"text":"Fai un video TikTok e postalo davvero!"},"nl":{"text":"Maak een TikTok-video en post het echt!"},"pl":{"text":"Nagraj filmik na TikToka i opublikuj go naprawde!"},"pt":{"text":"Faz um video TikTok e publica mesmo!"},"tr":{"text":"TikTok videosu cek ve gercekten paylas!"},"ar":{"text":"صور فيديو تيك توك وانشره فعلا!"}}', '3', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lauf einmal um das Gebaeude und schrei dabei deinen Namen!"},"en":{"text":"Run around the building while shouting your name!"},"es":{"text":"Corre alrededor del edificio gritando tu nombre!"},"fr":{"text":"Fais le tour du batiment en criant ton prenom!"},"it":{"text":"Corri intorno all\\"},"nl":{"text":"Ren om het gebouw terwijl je je naam schreeuwt!"},"pl":{"text":"Obiedz budynek krzyczac swoje imie!"},"pt":{"text":"Corre a volta do predio a gritar o teu nome!"},"tr":{"text":"Binaniñ etrafinda adini haykiarak kos!"},"ar":{"text":"اركض حول المبنى وانت تصرخ باسمك!"}}', '3', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lass dir von der Gruppe eine Aufgabe geben, die du morgen erledigen musst!"},"en":{"text":"Let the group give you a task to complete tomorrow!"},"es":{"text":"Deja que el grupo te ponga una tarea para manana!"},"fr":{"text":"Laisse le groupe te donner un defi pour demain!"},"it":{"text":"Lascia che il gruppo ti dia un compito per domani!"},"nl":{"text":"Laat de groep je een opdracht geven voor morgen!"},"pl":{"text":"Pozwol grupie dac ci zadanie do wykonania jutro!"},"pt":{"text":"Deixa o grupo dar-te uma tarefa para amanha!"},"tr":{"text":"Grubun yarin icin sana gorev vermesine izin ver!"},"ar":{"text":"دع المجموعة تعطيك مهمة لغد!"}}', '3', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Spreche 2 Minuten lang wie ein Pirat!"},"en":{"text":"Talk like a pirate for 2 minutes!"},"es":{"text":"Habla como un pirata durante 2 minutos!"},"fr":{"text":"Parle comme un pirate pendant 2 minutes!"},"it":{"text":"Parla come un pirata per 2 minuti!"},"nl":{"text":"Praat als een piraat voor 2 minuten!"},"pl":{"text":"Mow jak pirat przez 2 minuty!"},"pt":{"text":"Fala como pirata durante 2 minutos!"},"tr":{"text":"2 dakika korsan gibi konus!"},"ar":{"text":"تحدث كقرصان لمدة دقيقتين!"}}', '1', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach 20 Sekunden lang den Floss-Dance!"},"en":{"text":"Do the floss dance for 20 seconds!"},"es":{"text":"Haz el baile del floss durante 20 segundos!"},"fr":{"text":"Fais la danse du floss pendant 20 secondes!"},"it":{"text":"Fai il ballo del floss per 20 secondi!"},"nl":{"text":"Doe de floss-dans voor 20 seconden!"},"pl":{"text":"Tancz floss przez 20 sekund!"},"pt":{"text":"Faz a danca do floss durante 20 segundos!"},"tr":{"text":"20 saniye floss dansi yap!"},"ar":{"text":"ارقص الفلوس لمدة 20 ثانية!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Rufe jemanden an und frage, ob sein Kuehlschrank laeuft!"},"en":{"text":"Call someone and ask if their refrigerator is running!"},"es":{"text":"Llama a alguien y pregunta si su nevera esta corriendo!"},"fr":{"text":"Appelle quelqu\\"},"it":{"text":"Chiama qualcuno e chiedi se il suo frigo sta correndo!"},"nl":{"text":"Bel iemand en vraag of hun koelkast loopt!"},"pl":{"text":"Zadzwon do kogos i zapytaj, czy jego lodowka biega!"},"pt":{"text":"Liga a alguem e pergunta se o frigorifico esta a correr!"},"tr":{"text":"Birini ara ve buzdolabinin yuruyup yurumedini sor!"},"ar":{"text":"اتصل بشخص واساله ان كانت ثلاجته تجري!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach eine Liebeserklaerung an ein Moebelstück!"},"en":{"text":"Make a love declaration to a piece of furniture!"},"es":{"text":"Declara tu amor a un mueble!"},"fr":{"text":"Fais une declaration d\\"},"it":{"text":"Dichiara il tuo amore a un mobile!"},"nl":{"text":"Verklaar je liefde aan een meubel!"},"pl":{"text":"Wyznaj milosc meblowi!"},"pt":{"text":"Declara o teu amor a um movel!"},"tr":{"text":"Bir mobilyaya ask ilan et!"},"ar":{"text":"اعلن حبك لقطعة اثاث!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Iss einen Loeffel Senf oder Ketchup pur!"},"en":{"text":"Eat a spoonful of mustard or ketchup!"},"es":{"text":"Come una cucharada de mostaza o ketchup!"},"fr":{"text":"Mange une cuillere de moutarde ou de ketchup!"},"it":{"text":"Mangia un cucchiaio di senape o ketchup!"},"nl":{"text":"Eet een lepel mosterd of ketchup!"},"pl":{"text":"Zjedz lyzke musztardy lub ketchupu!"},"pt":{"text":"Come uma colher de mostarda ou ketchup!"},"tr":{"text":"Bir kasik hardal veya ketcap ye!"},"ar":{"text":"كل ملعقة خردل او كاتشب!"}}', '2', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle einen Witz — wenn niemand lacht, mach 10 Liegestütze!"},"en":{"text":"Tell a joke — if nobody laughs, do 10 push-ups!"},"es":{"text":"Cuenta un chiste — si nadie se rie, haz 10 flexiones!"},"fr":{"text":"Raconte une blague — si personne ne rit, fais 10 pompes!"},"it":{"text":"Racconta una barzelletta — se nessuno ride, fai 10 flessioni!"},"nl":{"text":"Vertel een mop — als niemand lacht, doe 10 push-ups!"},"pl":{"text":"Opowiedz dowcip — jesli nikt sie nie zasmieje, zrob 10 pompek!"},"pt":{"text":"Conta uma piada — se ninguem rir, faz 10 flexoes!"},"tr":{"text":"Fikra anlat — kimse gulmezse 10 sinav cek!"},"ar":{"text":"احك نكتة — اذا لم يضحك احد اعمل 10 ضغطات!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach ein Foto mit dem verruecktesten Gesicht und setze es als Profilbild!"},"en":{"text":"Take a photo with the craziest face and set it as your profile pic!"},"es":{"text":"Hazte una foto con la cara mas loca y ponla de perfil!"},"fr":{"text":"Prends une photo avec la tete la plus folle et mets-la en profil!"},"it":{"text":"Fai una foto con la faccia piu pazza e mettila come profilo!"},"nl":{"text":"Maak een foto met het gekste gezicht en stel het in als profielfoto!"},"pl":{"text":"Zrob zdjecie z najszalensza mina i ustaw jako profilowe!"},"pt":{"text":"Tira uma foto com a cara mais louca e coloca como perfil!"},"tr":{"text":"En cilgin yuzle foto cek ve profil yap!"},"ar":{"text":"التقط صورة باجنن وجه وضعها كبروفايل!"}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sprich die nächsten 2 Runden nur in der dritten Person!"},"en":{"text":"Speak in the third person for the next 2 rounds!"},"es":{"text":"Habla en tercera persona las proximas 2 rondas!"},"fr":{"text":"Parle a la troisieme personne les 2 prochains tours!"},"it":{"text":"Parla in terza persona per i prossimi 2 turni!"},"nl":{"text":"Praat in de derde persoon de komende 2 rondes!"},"pl":{"text":"Mow o sobie w trzeciej osobie przez 2 nastepne rundy!"},"pt":{"text":"Fala na terceira pessoa nas proximas 2 rondas!"},"tr":{"text":"Sonraki 2 tur ucuncu sahis olarak konus!"},"ar":{"text":"تحدث بصيغة الغائب في الجولتين القادمتين!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Fuehre einen erfundenen Zaubertrick vor!"},"en":{"text":"Perform a magic trick you just made up!"},"es":{"text":"Haz un truco de magia inventado!"},"fr":{"text":"Fais un tour de magie invente!"},"it":{"text":"Fai un trucco di magia inventato!"},"nl":{"text":"Voer een verzonnen goocheltruc op!"},"pl":{"text":"Wykonaj wymyslona sztuczke magiczna!"},"pt":{"text":"Faz um truque de magia inventado!"},"tr":{"text":"Uydurma bir sihirbazlik numarasi yap!"},"ar":{"text":"اعمل خدعة سحرية من اختراعك!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach ein 10-Sekunden-Workout und zaehle dabei auf Japanisch!"},"en":{"text":"Do a 10-second workout and count in Japanese!"},"es":{"text":"Haz un entreno de 10 segundos contando en japones!"},"fr":{"text":"Fais un workout de 10 secondes en comptant en japonais!"},"it":{"text":"Fai un workout di 10 secondi contando in giapponese!"},"nl":{"text":"Doe een 10-seconden workout en tel in het Japans!"},"pl":{"text":"Zrob 10-sekundowy trening liczac po japonsku!"},"pt":{"text":"Faz um treino de 10 segundos contando em japones!"},"tr":{"text":"10 saniyelik antrenman yap, Japonca say!"},"ar":{"text":"اعمل تمرين 10 ثوان وعد باليابانية!"}}', '1', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Imitiere deinen besten Freund — die anderen muessen raten!"},"en":{"text":"Imitate your best friend — the others have to guess!"},"es":{"text":"Imita a tu mejor amigo — los demas deben adivinar!"},"fr":{"text":"Imite ton meilleur ami — les autres doivent deviner!"},"it":{"text":"Imita il tuo migliore amico — gli altri devono indovinare!"},"nl":{"text":"Doe je beste vriend na — de anderen moeten raden!"},"pl":{"text":"Nasladuj najlepszego przyjacela — reszta musi zgadnac!"},"pt":{"text":"Imita o teu melhor amigo — os outros tem de adivinhar!"},"tr":{"text":"En iyi arkadasini taklit et — digerleri tahmin etsin!"},"ar":{"text":"قلد صديقك المقرب — والباقي يخمنون!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Schick der Person, die du zuletzt angerufen hast, ein Herz!"},"en":{"text":"Send a heart to the last person you called!"},"es":{"text":"Envia un corazon a la ultima persona que llamaste!"},"fr":{"text":"Envoie un coeur a la derniere personne que tu as appelee!"},"it":{"text":"Manda un cuore all\\"},"nl":{"text":"Stuur een hartje naar de laatste persoon die je belde!"},"pl":{"text":"Wyslij serduszko ostatniej osobie, do ktorej dzwoniles!"},"pt":{"text":"Envia um coracao a ultima pessoa a quem ligaste!"},"tr":{"text":"Son aradigin kisiye kalp gonder!"},"ar":{"text":"ارسل قلبا لاخر شخص اتصلت به!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Fuehre einen Striptease vor — aber nur mit Socken!"},"en":{"text":"Do a striptease — but only with your socks!"},"es":{"text":"Haz un striptease — pero solo con los calcetines!"},"fr":{"text":"Fais un striptease — mais seulement avec les chaussettes!"},"it":{"text":"Fai uno striptease — ma solo con i calzini!"},"nl":{"text":"Doe een striptease — maar alleen met je sokken!"},"pl":{"text":"Zrob striptiz — ale tylko ze skarpetkami!"},"pt":{"text":"Faz um striptease — mas so com as meias!"},"tr":{"text":"Striptiz yap — ama sadece coraplarla!"},"ar":{"text":"اعمل ستربتيز — بس بالجوارب!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sing das ABC-Lied so schnell du kannst!"},"en":{"text":"Sing the ABC song as fast as you can!"},"es":{"text":"Canta el abecedario lo mas rapido que puedas!"},"fr":{"text":"Chante l\\"},"it":{"text":"Canta l\\"},"nl":{"text":"Zing het alfabet zo snel als je kunt!"},"pl":{"text":"Zaspiewaj alfabet jak najszybciej!"},"pt":{"text":"Canta o abecedario o mais rapido possivel!"},"tr":{"text":"Alfabeyi olabildigince hizli soyle!"},"ar":{"text":"غن الابجدية باسرع ما يمكن!"}}', '1', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach eine Verbeugung vor jeder Person in der Runde!"},"en":{"text":"Take a bow to every person in the group!"},"es":{"text":"Haz una reverencia a cada persona del grupo!"},"fr":{"text":"Fais une reverence a chaque personne du groupe!"},"it":{"text":"Fai un inchino a ogni persona del gruppo!"},"nl":{"text":"Maak een buiging voor elke persoon in de groep!"},"pl":{"text":"Uklonij sie kazdej osobie w grupie!"},"pt":{"text":"Faz uma venia a cada pessoa do grupo!"},"tr":{"text":"Gruptaki her kisiye selam ver!"},"ar":{"text":"انحن لكل شخص في المجموعة!"}}', '1', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lass die Gruppe entscheiden, was du als Nächstes trinkst!"},"en":{"text":"Let the group decide what you drink next!"},"es":{"text":"Deja que el grupo decida que bebes a continuacion!"},"fr":{"text":"Laisse le groupe decider de ta prochaine boisson!"},"it":{"text":"Lascia che il gruppo decida cosa bevi dopo!"},"nl":{"text":"Laat de groep beslissen wat je hierna drinkt!"},"pl":{"text":"Pozwol grupie zdecydowac, co pijesz nastepne!"},"pt":{"text":"Deixa o grupo decidir o que bebes a seguir!"},"tr":{"text":"Grubun ne icecegine karar vermesine izin ver!"},"ar":{"text":"دع المجموعة تقرر ماذا تشرب بعد!"}}', '2', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle 30 Sekunden lang Unsinn, als waere es eine Nachrichtensendung!"},"en":{"text":"Talk nonsense for 30 seconds like it is a news broadcast!"},"es":{"text":"Habla tonterias 30 segundos como si fuera un telediario!"},"fr":{"text":"Parle n\\"},"it":{"text":"Parla a vanvera per 30 secondi come un telegiornale!"},"nl":{"text":"Praat 30 seconden onzin alsof het een journaal is!"},"pl":{"text":"Mow bzdury przez 30 sekund jakbys czytaw wiadomosci!"},"pt":{"text":"Fala disparates 30 segundos como se fosse um telejornal!"},"tr":{"text":"30 saniye sacmalık konus sanki habermiş gibi!"},"ar":{"text":"تحدث هراء 30 ثانية كانه نشرة اخبار!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach ein Geräusch wie ein Alien für15 Sekunden!"},"en":{"text":"Make alien sounds for 15 seconds!"},"es":{"text":"Haz sonidos de alien durante 15 segundos!"},"fr":{"text":"Fais des sons d\\"},"it":{"text":"Fai suoni da alieno per 15 secondi!"},"nl":{"text":"Maak 15 seconden buitenaardse geluiden!"},"pl":{"text":"Wydawaj dzwieki kosmity przez 15 sekund!"},"pt":{"text":"Faz sons de alienigena durante 15 segundos!"},"tr":{"text":"15 saniye uzayli sesleri cikar!"},"ar":{"text":"اصدر اصوات فضائي لمدة 15 ثانية!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Steh auf und halte eine Wahlrede — du kandidierst als Buergermeister!"},"en":{"text":"Stand up and give a campaign speech — you are running for mayor!"},"es":{"text":"Levantate y da un discurso electoral — te presentas a alcalde!"},"fr":{"text":"Leve-toi et fais un discours de campagne — tu es candidat maire!"},"it":{"text":"Alzati e tieni un comizio — ti candidi a sindaco!"},"nl":{"text":"Sta op en houd een verkiezingstoespraak — je bent kandidaat-burgemeester!"},"pl":{"text":"Wstan i wyglos przemowienie wyborcze — kandudujesz na burmistrza!"},"pt":{"text":"Levanta-te e faz um discurso eleitoral — es candidato a presidente!"},"tr":{"text":"Ayaga kalk ve secim konusmasi yap — belediye baskani adayisin!"},"ar":{"text":"قف والق خطاب انتخابي — انت مرشح للرئاسة!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sende der dritten Person in deiner Kontaktliste \"Ich vermisse dich\"!"},"en":{"text":"Send the third person in your contacts \"I miss you\"!"},"es":{"text":"Envia al tercer contacto de tu lista \"Te echo de menos\"!"},"fr":{"text":"Envoie au 3e contact de ta liste \"Tu me manques\"!"},"it":{"text":"Manda al 3° contatto della lista \"Mi manchi\"!"},"nl":{"text":"Stuur het 3e contact in je lijst \"Ik mis je\"!"},"pl":{"text":"Wyslij 3. kontaktowi na liscie \"Tesknie za toba\"!"},"pt":{"text":"Envia ao 3o contacto da lista \"Tenho saudades tuas\"!"},"tr":{"text":"Listenindeki 3. kisiye \"Seni ozledim\" gonder!"},"ar":{"text":"ارسل لثالث جهة اتصال \"اشتقت لك\"!"}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach den Macarena-Tanz vor!"},"en":{"text":"Do the Macarena!"},"es":{"text":"Baila la Macarena!"},"fr":{"text":"Danse la Macarena!"},"it":{"text":"Balla la Macarena!"},"nl":{"text":"Dans de Macarena!"},"pl":{"text":"Zatancz Macarene!"},"pt":{"text":"Danca a Macarena!"},"tr":{"text":"Macarena dans et!"},"ar":{"text":"ارقص الماكارينا!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sprich 1 Minute lang ohne den Buchstaben \"E\" zu verwenden!"},"en":{"text":"Speak for 1 minute without using the letter E!"},"es":{"text":"Habla 1 minuto sin usar la letra E!"},"fr":{"text":"Parle pendant 1 minute sans utiliser la lettre E!"},"it":{"text":"Parla per 1 minuto senza usare la lettera E!"},"nl":{"text":"Praat 1 minuut zonder de letter E te gebruiken!"},"pl":{"text":"Mow przez 1 minute bez uzywania litery E!"},"pt":{"text":"Fala 1 minuto sem usar a letra E!"},"tr":{"text":"1 dakika E harfi kullanmadan konus!"},"ar":{"text":"تحدث دقيقة بدون حرف الالف!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach ein Selfie mit geschlossenen Augen und poste es!"},"en":{"text":"Take a selfie with your eyes closed and post it!"},"es":{"text":"Hazte un selfie con los ojos cerrados y publicalo!"},"fr":{"text":"Prends un selfie yeux fermes et poste-le!"},"it":{"text":"Fai un selfie ad occhi chiusi e postalo!"},"nl":{"text":"Maak een selfie met je ogen dicht en post het!"},"pl":{"text":"Zrob selfie z zamknietymi oczami i opublikuj!"},"pt":{"text":"Tira uma selfie de olhos fechados e publica!"},"tr":{"text":"Gozleri kapali selfie cek ve paylas!"},"ar":{"text":"التقط سيلفي وعيونك مغلقة وانشره!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Fuehre vor, wie du morgens aufstehst — in Zeitlupe!"},"en":{"text":"Act out how you get up in the morning — in slow motion!"},"es":{"text":"Actua como te levantas por la manana — en camara lenta!"},"fr":{"text":"Mime comment tu te leves le matin — au ralenti!"},"it":{"text":"Mima come ti alzi la mattina — al rallentatore!"},"nl":{"text":"Doe voor hoe je \\"},"pl":{"text":"Pokaz jak wstajesz rano — w zwolnionym tempie!"},"pt":{"text":"Mostra como acordas de manha — em camara lenta!"},"tr":{"text":"Sabah nasil kalktini goster — agir cekimde!"},"ar":{"text":"مثل كيف تستيقظ صباحا — بالحركة البطيئة!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Spiele Luft-Schlagzeug zu einem Song, den die Gruppe waehlt!"},"en":{"text":"Play air drums to a song the group picks!"},"es":{"text":"Toca la bateria imaginaria con una cancion que elija el grupo!"},"fr":{"text":"Joue de la batterie imaginaire sur un morceau choisi par le groupe!"},"it":{"text":"Suona la batteria immaginaria con un brano scelto dal gruppo!"},"nl":{"text":"Speel luchtdrums bij een liedje dat de groep kiest!"},"pl":{"text":"Zagraj na powietrznej perkusji do piosenki wybranej przez grupe!"},"pt":{"text":"Toca bateria imaginaria com uma musica escolhida pelo grupo!"},"tr":{"text":"Grubun sectigi sarikiyla hava davulu cal!"},"ar":{"text":"اعزف درامز وهمية على اغنية تختارها المجموعة!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach 15 Sekunden lang Babygeraeusche!"},"en":{"text":"Make baby sounds for 15 seconds!"},"es":{"text":"Haz sonidos de bebe durante 15 segundos!"},"fr":{"text":"Fais des bruits de bebe pendant 15 secondes!"},"it":{"text":"Fai versi da neonato per 15 secondi!"},"nl":{"text":"Maak 15 seconden babygeluiden!"},"pl":{"text":"Wydawaj dzwieki niemowlecia przez 15 sekund!"},"pt":{"text":"Faz sons de bebe durante 15 segundos!"},"tr":{"text":"15 saniye bebek sesleri cikar!"},"ar":{"text":"اصدر اصوات طفل لمدة 15 ثانية!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Halte eine dramatische Abschiedsrede, als würdest du ins Exil gehen!"},"en":{"text":"Give a dramatic farewell speech as if going into exile!"},"es":{"text":"Da un discurso dramatico de despedida como si te fueras al exilio!"},"fr":{"text":"Fais un discours dramatique d\\"},"it":{"text":"Tieni un discorso d\\"},"nl":{"text":"Houd een dramatische afscheidstoespraak alsof je in ballingschap gaat!"},"pl":{"text":"Wyglos dramatyczna mowe pozegnalna jakbys szedl na wygnanie!"},"pt":{"text":"Faz um discurso de despedida dramatico como se fosses para o exilio!"},"tr":{"text":"Surguene gidiyormus gibi dramatik veda konusmasi yap!"},"ar":{"text":"الق خطاب وداع درامي كانك ذاهب للمنفى!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lass die Person rechts von dir deinen Bart oder dein Haar stylen!"},"en":{"text":"Let the person to your right style your hair!"},"es":{"text":"Deja que la persona de tu derecha te peine!"},"fr":{"text":"Laisse la personne a ta droite te coiffer!"},"it":{"text":"Lascia che la persona alla tua destra ti pettini!"},"nl":{"text":"Laat de persoon rechts je haar stylen!"},"pl":{"text":"Pozwol osobie po prawej uczesac ci wlosy!"},"pt":{"text":"Deixa a pessoa a tua direita pentear-te!"},"tr":{"text":"Sagindaki kisinin sacini sekillendirmesine izin ver!"},"ar":{"text":"دع الشخص على يمينك يصفف شعرك!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach deinen besten Catwalk durch den Raum!"},"en":{"text":"Do your best catwalk across the room!"},"es":{"text":"Haz tu mejor pasarela por la habitacion!"},"fr":{"text":"Fais ton plus beau defile dans la piece!"},"it":{"text":"Fai la tua migliore sfilata per la stanza!"},"nl":{"text":"Doe je beste catwalk door de kamer!"},"pl":{"text":"Zrob najlepszy catwalk po pokoju!"},"pt":{"text":"Faz o teu melhor desfile pela sala!"},"tr":{"text":"Odada en iyi podyum yuruyusunu yap!"},"ar":{"text":"اعمل افضل استعراض ازياء في الغرفة!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle eine Geschichte, in der du der Held bist!"},"en":{"text":"Tell a story where you are the hero!"},"es":{"text":"Cuenta una historia donde tu eres el heroe!"},"fr":{"text":"Raconte une histoire ou tu es le heros!"},"it":{"text":"Racconta una storia dove tu sei l\\"},"nl":{"text":"Vertel een verhaal waarin jij de held bent!"},"pl":{"text":"Opowiedz historie, w ktorej jestes bohaterem!"},"pt":{"text":"Conta uma historia onde tu es o heroi!"},"tr":{"text":"Kahraman oldugun bir hikaye anlat!"},"ar":{"text":"احك قصة انت فيها البطل!"}}', '1', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sprich wie ein Nachrichtensprecher und berichte überdie letzte Runde!"},"en":{"text":"Speak like a news anchor and report on the last round!"},"es":{"text":"Habla como presentador de noticias e informa de la ultima ronda!"},"fr":{"text":"Parle comme un presentateur de JT et commente le dernier tour!"},"it":{"text":"Parla come un telegiornalista e commenta l\\"},"nl":{"text":"Praat als een nieuwslezer en verslag over de laatste ronde!"},"pl":{"text":"Mow jak prezenter wiadomosci i relacjonuj ostatnia runde!"},"pt":{"text":"Fala como apresentador de noticias e comenta a ultima ronda!"},"tr":{"text":"Haber spikeri gibi konus ve son turu yorumla!"},"ar":{"text":"تحدث كمذيع اخبار وعلق على الجولة الاخيرة!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach 30 Sekunden lang Tai Chi!"},"en":{"text":"Do tai chi for 30 seconds!"},"es":{"text":"Haz tai chi durante 30 segundos!"},"fr":{"text":"Fais du tai-chi pendant 30 secondes!"},"it":{"text":"Fai tai chi per 30 secondi!"},"nl":{"text":"Doe 30 seconden tai chi!"},"pl":{"text":"Zrob tai chi przez 30 sekund!"},"pt":{"text":"Faz tai chi durante 30 segundos!"},"tr":{"text":"30 saniye tai chi yap!"},"ar":{"text":"اعمل تاي تشي لمدة 30 ثانية!"}}', '1', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Fuehre einen unsichtbaren Hund Gassi — durch den ganzen Raum!"},"en":{"text":"Walk an invisible dog — through the entire room!"},"es":{"text":"Pasea a un perro invisible por toda la habitacion!"},"fr":{"text":"Promene un chien invisible dans toute la piece!"},"it":{"text":"Porta a spasso un cane invisibile per tutta la stanza!"},"nl":{"text":"Loop met een onzichtbare hond door de hele kamer!"},"pl":{"text":"Wyprowadz niewidzialnego psa po calym pokoju!"},"pt":{"text":"Passeia um cao invisivel pela sala toda!"},"tr":{"text":"Gorunmez bir kopegi tum odada gezdirs!"},"ar":{"text":"تمشى مع كلب وهمي في كل الغرفة!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sage \"Ich liebe dich\" zur Person gegenüber, ohne zu lachen!"},"en":{"text":"Say \"I love you\" to the person across from you without laughing!"},"es":{"text":"Dile \"Te quiero\" a la persona de enfrente sin reirte!"},"fr":{"text":"Dis \"Je t\\"},"it":{"text":"Di \"Ti amo\" alla persona di fronte senza ridere!"},"nl":{"text":"Zeg \"Ik hou van je\" tegen de persoon tegenover je zonder te lachen!"},"pl":{"text":"Powiedz \"Kocham cie\" do osoby naprzeciwko bez smiechu!"},"pt":{"text":"Diz \"Amo-te\" a pessoa a frente sem rir!"},"tr":{"text":"Karsnindaki kisiye gulmeden \"Seni seviyorum\" de!"},"ar":{"text":"قل \"احبك\" للشخص المقابل بدون ضحك!"}}', '3', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Tanze Walzer — alleine!"},"en":{"text":"Dance a waltz — by yourself!"},"es":{"text":"Baila un vals — tu solo!"},"fr":{"text":"Danse une valse — tout seul!"},"it":{"text":"Balla un valzer — da solo!"},"nl":{"text":"Dans een wals — in je eentje!"},"pl":{"text":"Zatancz walca — sam!"},"pt":{"text":"Danca uma valsa — sozinho!"},"tr":{"text":"Tek basina vals dans et!"},"ar":{"text":"ارقص فالس — لوحدك!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Versuche einen Zungenbrecher 5 Mal hintereinander!"},"en":{"text":"Try a tongue twister 5 times in a row!"},"es":{"text":"Intenta un trabalenguas 5 veces seguidas!"},"fr":{"text":"Essaie un virelangue 5 fois de suite!"},"it":{"text":"Prova uno scioglilingua 5 volte di fila!"},"nl":{"text":"Probeer een tongbreker 5 keer achter elkaar!"},"pl":{"text":"Sprobuj lamaniec jezykowy 5 razy z rzedu!"},"pt":{"text":"Tenta um trava-linguas 5 vezes seguidas!"},"tr":{"text":"Bir tekerlemeyi 5 kez ust uste dene!"},"ar":{"text":"جرب سجعة 5 مرات متتالية!"}}', '1', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach einen Wettlauf zum nächsten Baum und zurück!"},"en":{"text":"Race to the nearest tree and back!"},"es":{"text":"Corre hasta el arbol mas cercano y vuelve!"},"fr":{"text":"Cours jusqu\\"},"it":{"text":"Corri fino all\\"},"nl":{"text":"Ren naar de dichtstbijzijnde boom en terug!"},"pl":{"text":"Pobiegnij do najblizszego drzewa i wroc!"},"pt":{"text":"Corre ate a arvore mais proxima e volta!"},"tr":{"text":"En yakin agaca kos ve geri don!"},"ar":{"text":"اركض لاقرب شجرة وارجع!"}}', '1', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Haenge für30 Sekunden kopfüber überdie Sofalehne!"},"en":{"text":"Hang upside down over the couch for 30 seconds!"},"es":{"text":"Cuelgate boca abajo del sofa durante 30 segundos!"},"fr":{"text":"Pends-toi la tete en bas du canape pendant 30 secondes!"},"it":{"text":"Penzola a testa in giu dal divano per 30 secondi!"},"nl":{"text":"Hang 30 seconden ondersteboven over de bank!"},"pl":{"text":"Zwis glowa w dol z kanapy przez 30 sekund!"},"pt":{"text":"Fica pendurado de cabeca para baixo no sofa durante 30 segundos!"},"tr":{"text":"30 saniye koltuktan bas asagi sarkis!"},"ar":{"text":"تعلق راسا على عقب من الكنبة 30 ثانية!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Geh zum Fenster und winke Passanten zu!"},"en":{"text":"Go to the window and wave at people passing by!"},"es":{"text":"Ve a la ventana y saluda a los que pasen!"},"fr":{"text":"Va a la fenetre et fais coucou aux passants!"},"it":{"text":"Vai alla finestra e saluta i passanti!"},"nl":{"text":"Ga naar het raam en zwaai naar voorbijgangers!"},"pl":{"text":"Idz do okna i pomachaj przechodniom!"},"pt":{"text":"Vai a janela e acena aos passantes!"},"tr":{"text":"Pencereye git ve gecenlere el salla!"},"ar":{"text":"اذهب للنافذة ولوح للمارة!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach eine Instagram-Story mit einem peinlichen Filter!"},"en":{"text":"Post an Instagram story with an embarrassing filter!"},"es":{"text":"Sube una story de Instagram con un filtro vergonzoso!"},"fr":{"text":"Poste une story Instagram avec un filtre genant!"},"it":{"text":"Pubblica una story Instagram con un filtro imbarazzante!"},"nl":{"text":"Post een Instagram-story met een gênant filter!"},"pl":{"text":"Opublikuj story na Instagramie z zenujacym filtrem!"},"pt":{"text":"Publica uma story no Instagram com um filtro embaracoso!"},"tr":{"text":"Utandirici bir filtreyle Instagram story paylas!"},"ar":{"text":"انشر ستوري انستغرام بفلتر محرج!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Sage jedem in der Runde, was du an ihm/ihr am meisten bewunderst!"},"en":{"text":"Tell everyone in the group what you admire most about them!"},"es":{"text":"Dile a cada persona del grupo lo que mas admiras de ella!"},"fr":{"text":"Dis a chaque personne du groupe ce que tu admires le plus chez elle!"},"it":{"text":"Di a ogni persona del gruppo cosa ammiri di piu di lei!"},"nl":{"text":"Vertel iedereen in de groep wat je het meest aan hen bewondert!"},"pl":{"text":"Powiedz kazdemu w grupie, co w nim najbardziej podziwiasz!"},"pt":{"text":"Diz a cada pessoa do grupo o que mais admiras nela!"},"tr":{"text":"Gruptaki herkese en cok neyi takdir ettigini soyle!"},"ar":{"text":"قل لكل شخص في المجموعة ما تعجبك فيه اكثر!"}}', '2', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Erzähle einen Witz auf Englisch — mit deutschem Akzent!"},"en":{"text":"Tell a joke in another language — with a silly accent!"},"es":{"text":"Cuenta un chiste en otro idioma — con acento exagerado!"},"fr":{"text":"Raconte une blague dans une autre langue — avec un accent exagere!"},"it":{"text":"Racconta una barzelletta in un\\"},"nl":{"text":"Vertel een mop in een andere taal — met een overdreven accent!"},"pl":{"text":"Opowiedz dowcip w innym jezyku — z przesadnym akcentem!"},"pt":{"text":"Conta uma piada noutra lingua — com sotaque exagerado!"},"tr":{"text":"Baska bir dilde fikra anlat — abartili aksanla!"},"ar":{"text":"احك نكتة بلغة اخرى — بلهجة مبالغ فيها!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach eine Planke und halte sie, bis du die nächste Frage beantwortet hast!"},"en":{"text":"Hold a plank until you answer the next question!"},"es":{"text":"Haz plancha y mantela hasta contestar la siguiente pregunta!"},"fr":{"text":"Fais la planche et tiens jusqu\\"},"it":{"text":"Fai il plank e mantienilo finche non rispondi alla prossima domanda!"},"nl":{"text":"Houd een plank aan tot je de volgende vraag hebt beantwoord!"},"pl":{"text":"Zrob deske i trzymaj ja, az odpowiesz na nastepne pytanie!"},"pt":{"text":"Faz prancha e aguenta ate responderes a proxima pergunta!"},"tr":{"text":"Plank yap ve sonraki soruyu cevaplayana kadar tut!"},"ar":{"text":"اعمل بلانك وامسكه حتى تجيب على السؤال التالي!"}}', '2', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Schau der Person links in die Augen und sage etwas Nettes — ohne zu lachen!"},"en":{"text":"Look the person to your left in the eyes and say something nice — no laughing!"},"es":{"text":"Mira a la persona de tu izquierda a los ojos y dile algo bonito — sin reirte!"},"fr":{"text":"Regarde la personne a gauche dans les yeux et dis quelque chose de gentil — sans rire!"},"it":{"text":"Guarda la persona alla tua sinistra negli occhi e dille qualcosa di carino — senza ridere!"},"nl":{"text":"Kijk de persoon links in de ogen en zeg iets liefs — zonder te lachen!"},"pl":{"text":"Spojrz osobie po lewej w oczy i powiedz cos milego — bez smiechu!"},"pt":{"text":"Olha a pessoa a esquerda nos olhos e diz algo querido — sem rir!"},"tr":{"text":"Solundaki kisinin gozlerine bak ve guzel bir sey soyle — gulmeden!"},"ar":{"text":"انظر في عيون الشخص على يسارك وقل شيئا لطيفا — بدون ضحك!"}}', '2', 'Peinlich', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Fuehre ein unsichtbares Orchester!"},"en":{"text":"Conduct an invisible orchestra!"},"es":{"text":"Dirige una orquesta invisible!"},"fr":{"text":"Dirige un orchestre invisible!"},"it":{"text":"Dirigi un\\"},"nl":{"text":"Dirigeer een onzichtbaar orkest!"},"pl":{"text":"Dyryguj niewidzialna orkiestra!"},"pt":{"text":"Dirige uma orquestra invisivel!"},"tr":{"text":"Gorunmez bir orkestra yonet!"},"ar":{"text":"قد اوركسترا وهمية!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Ruf den letzten Kontakt in deinem Handy an und sag: Du bist mein Held!"},"en":{"text":"Call the last contact on your phone and say: You are my hero!"},"es":{"text":"Llama al ultimo contacto del movil y dile: Eres mi heroe!"},"fr":{"text":"Appelle le dernier contact de ton telephone et dis: Tu es mon heros!"},"it":{"text":"Chiama l\\"},"nl":{"text":"Bel het laatste contact op je telefoon en zeg: Jij bent mijn held!"},"pl":{"text":"Zadzwon do ostatniego kontaktu i powiedz: Jestes moim bohaterem!"},"pt":{"text":"Liga ao ultimo contacto e diz: Es o meu heroi!"},"tr":{"text":"Son kisiyi ara ve de ki: Sen benim kahramanimsim!"},"ar":{"text":"اتصل باخر جهة اتصال وقل: انت بطلي!"}}', '3', 'Mutig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Mach eine Aufwärmübung wie ein Profisportler — für30 Sekunden!"},"en":{"text":"Do warm-up exercises like a pro athlete — for 30 seconds!"},"es":{"text":"Haz calentamiento como un deportista profesional — 30 segundos!"},"fr":{"text":"Fais un echauffement comme un athlete professionnel — 30 secondes!"},"it":{"text":"Fai riscaldamento come un atleta professionista — 30 secondi!"},"nl":{"text":"Doe een warming-up als een profatleet — 30 seconden!"},"pl":{"text":"Zrob rozgrzewke jak profesjonalny sportowiec — 30 sekund!"},"pt":{"text":"Faz aquecimento como atleta profissional — 30 segundos!"},"tr":{"text":"Profesyonel sporcu gibi isinma yap — 30 saniye!"},"ar":{"text":"اعمل احماء كرياضي محترف — 30 ثانية!"}}', '1', 'Harmlos', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Versuche 20 Sekunden lang nicht zu blinzeln, während die anderen dich ablenken!"},"en":{"text":"Try not to blink for 20 seconds while the others distract you!"},"es":{"text":"Intenta no parpadear 20 segundos mientras los demas te distraen!"},"fr":{"text":"Essaie de ne pas cligner des yeux 20 secondes pendant que les autres te distraient!"},"it":{"text":"Prova a non battere le palpebre per 20 secondi mentre gli altri ti distraggono!"},"nl":{"text":"Probeer 20 seconden niet te knipperen terwijl de anderen je afleiden!"},"pl":{"text":"Sprobuj nie mrugac 20 sekund, gdy inni cie rozpraszaja!"},"pt":{"text":"Tenta nao piscar 20 segundos enquanto os outros te distraem!"},"tr":{"text":"Digerleri dikkatini dagitirken 20 saniye gozunu kirpmamaya calis!"},"ar":{"text":"حاول الا ترمش 20 ثانية بينما يشتتك الاخرون!"}}', '1', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Singe den Refrain eines Kinderlieds in Opernsaenger-Stimme!"},"en":{"text":"Sing the chorus of a nursery rhyme in an opera voice!"},"es":{"text":"Canta el estribillo de una cancion infantil con voz de opera!"},"fr":{"text":"Chante le refrain d\\"},"it":{"text":"Canta il ritornello di una filastrocca con voce da soprano!"},"nl":{"text":"Zing het refrein van een kinderliedje met operastem!"},"pl":{"text":"Zaspiewaj refren dzieciecej piosenki glosem operowym!"},"pt":{"text":"Canta o refrao de uma cancao infantil com voz de opera!"},"tr":{"text":"Bir cocuk sarkisinin nakratini opera sesiyle soyle!"},"ar":{"text":"غن لازمة اغنية اطفال بصوت اوبرا!"}}', '2', 'Lustig', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('truthdare', 'dare', '{"de":{"text":"Lass jemanden ein Wort auf deinen Arm schreiben!"},"en":{"text":"Let someone write a word on your arm!"},"es":{"text":"Deja que alguien escriba una palabra en tu brazo!"},"fr":{"text":"Laisse quelqu\\"},"it":{"text":"Lascia che qualcuno scriva una parola sul tuo braccio!"},"nl":{"text":"Laat iemand een woord op je arm schrijven!"},"pl":{"text":"Pozwol komus napisac slowo na twoim ramieniu!"},"pt":{"text":"Deixa alguem escrever uma palavra no teu braco!"},"tr":{"text":"Birinin koluna bir kelime yazmasina izin ver!"},"ar":{"text":"دع شخصا يكتب كلمة على ذراعك!"}}', '2', 'Peinlich', true);
